import{_ as a,o as l,c as i,f as e}from"./app-55c326ac.js";const o={},n=e('<ul><li><a href="#11-django%E7%9A%84%E4%BA%A7%E7%94%9F%E8%83%8C%E6%99%AF">1.1 Django的产生背景</a><ul><li><a href="#111-django%E7%9A%84%E5%88%9B%E5%BB%BA%E8%83%8C%E6%99%AF">1.1.1 Django的创建背景</a></li><li><a href="#%E6%80%BB%E7%BB%93">总结</a></li></ul></li></ul><h1 id="_1-1-django的产生背景" tabindex="-1"><a class="header-anchor" href="#_1-1-django的产生背景" aria-hidden="true">#</a> 1.1 Django的产生背景</h1><h2 id="_1-1-1-django的创建背景" tabindex="-1"><a class="header-anchor" href="#_1-1-1-django的创建背景" aria-hidden="true">#</a> 1.1.1 Django的创建背景</h2><p>开发一个web站点，需要做的工作，以及写那些组件呢：</p><ol><li>构建用户账户关系，实现web站点的登录与注册功能</li><li>定义数据表模型及实现访问功能</li><li>编写业务逻辑实现站点功能</li><li>实现后台管理功能</li><li>路由模型实现功能请求映射</li></ol><p>通常，不同的站点知识步骤3的业务逻辑不同, 其他的功能需求是类似的，甚至是完全一样的</p><p>如何把通用的组件或者模块组合在一起呢？</p><p>出现 web框架的概念，也是Django产生的背景</p><h2 id="总结" tabindex="-1"><a class="header-anchor" href="#总结" aria-hidden="true">#</a> 总结</h2><ol><li>主要内容</li><li>结论： <ul><li>Django:&quot;完美主义者的最终框架&quot;</li><li>Django：允许开发人员编写数据库驱动的web应用程序，而不需要从头开始编码</li><li>尽可能提供简单，易用且功能强大的功能模块</li><li>优点：快速高效，不需要使用者设计用户系统，搭建权限验证，不需要构建缓存体系，不需要编写大量重复的代码去完成后台管理的功能</li><li>使用Django框架从零搭建一个简单可运行的Web程序很快速</li></ul></li></ol>',10),r=[n];function d(t,h){return l(),i("div",null,r)}const c=a(o,[["render",d],["__file","1.1 Django背景.html.vue"]]);export{c as default};
